import streamlit as stfrom streamlit_gsheets import GSheetsConnectionimport pandas as pdfrom datetime import datetime, timedeltaimport urllib.parseimport plotly.express as pximport warnings# Gereksiz uyarıları gizlewarnings.filterwarnings("ignore")# --- 1. SAYFA AYARLARI ---st.set_page_config(    page_title="Bostanlı Çözüm VIP",     layout="wide",     page_icon="🏫",    initial_sidebar_state="collapsed" )# Tasarım (CSS)st.markdown("""    <style>    #MainMenu {visibility: hidden;}    footer {visibility: hidden;}    header {visibility: hidden;}    .stDeployButton {display:none;}    .stTabs [data-baseweb="tab-list"] {        gap: 15px;        background-color: #f0f2f6;        padding: 10px;        border-radius: 10px;    }    .stTabs [data-baseweb="tab"] {        height: 50px;        background-color: #ffffff;        border-radius: 5px;        font-weight: bold;    }    </style>    """, unsafe_allow_html=True)# --- 2. ŞİFRE SİSTEMİ ---def check_password():    if "user_role" not in st.session_state:        st.title("🔐 Kurumsal Yönetim Paneli")        pwd = st.text_input("Giriş Şifresi", type="password")        if st.button("Sisteme Giriş Yap"):            if pwd == "cozum35":                st.session_state["user_role"] = "admin"                st.rerun()            elif pwd == "personel35":                st.session_state["user_role"] = "staff"                st.rerun()            else:                st.error("❌ Hatalı şifre.")        return False    return Trueif check_password():    conn = st.connection("gsheets", type=GSheetsConnection)    role = st.session_state["user_role"]    def wa_link(tel, mesaj):        tel_str = str(tel).replace(" ", "").replace("-", "").replace("(", "").replace(")", "")        if tel_str.startswith("0"): tel_str = "90" + tel_str[1:]        elif not tel_str.startswith("90"): tel_str = "90" + tel_str        return f"https://wa.me/{tel_str}?text={urllib.parse.quote(mesaj)}"    # Üst Başlık    st.title(f"🏫 Bostanlı Çözüm VIP ({'Kurucu' if role == 'admin' else 'Personel'} Paneli)")    # --- 3. SEKMELER ---    if role == "admin":        tabs = st.tabs(["📊 Kurucu Raporu", "📈 Gelişmiş Analiz"])    else:        tabs = st.tabs(["📞 Veli Görüşmeleri", "💰 Kasa İşlemleri", "🚨 Günlük Olaylar", "📝 Raporu İlet"])    # --- 🔵 PERSONEL PANELİ (Giriş Alanı Eklendi) ---    if role == "staff":        with tabs[0]: # Veli Görüşmeleri            st.header("📞 Veli Görüşme Kayıt")            try:                df_v = conn.read(worksheet="gorusmeler", ttl=0)            except:                df_v = pd.DataFrame(columns=["Tarih", "Veli Ad Soyad", "Öğrenci Ad Soyad", "Telefon", "Konu", "Durum", "Notlar", "Görüşmeyi Yapan"])                        with st.form("v_form", clear_on_submit=True):                v_t = st.date_input("Tarih", datetime.now())                c1, c2 = st.columns(2)                v_a = c1.text_input("Veli Ad Soyad *")                o_a = c1.text_input("Öğrenci Ad Soyad *")                v_tel = c2.text_input("Telefon *")                v_ko = c2.selectbox("Konu *", ["Seçiniz...", "YKS Hazırlık", "LGS Hazırlık", "Ara Sınıf", "Kamp", "Diğer"])                                # YENİ ALAN: GÖRÜŞMEYİ YAPAN                v_yapan = st.selectbox("Görüşmeyi Yapan Personel *", ["Seçiniz...", "Tufan Bey", "Eğitim Koordinatörü", "Rehberlik", "Ofis Yönetimi", "Diğer"])                                v_du = st.selectbox("Durum *", ["Beklemede", "Olumlu", "Olumsuz", "Kayıt Tamamlandı", "İptal"])                v_no = st.text_area("Görüşme Notları")                                if st.form_submit_button("Kaydet"):                    if v_a and o_a and v_ko != "Seçiniz..." and v_yapan != "Seçiniz...":                        new = pd.DataFrame([{"Tarih": v_t.strftime("%Y-%m-%d"), "Veli Ad Soyad": v_a, "Öğrenci Ad Soyad": o_a, "Telefon": v_tel, "Konu": v_ko, "Durum": v_du, "Notlar": v_no, "Görüşmeyi Yapan": v_yapan}])                        conn.update(worksheet="gorusmeler", data=pd.concat([df_v, new], ignore_index=True))                        st.success(f"✅ {v_a} kaydı, {v_yapan} tarafından sisteme işlendi.")                    else:                        st.error("⚠️ Lütfen zorunlu alanları (*) doldurun!")            st.subheader("🔍 Kayıtları Düzenle")            st.data_editor(df_v, num_rows="dynamic", key="v_edit")            if st.button("Görüşmeleri Güncelle"): conn.update(worksheet="gorusmeler", data=st.session_state.v_edit)        # Diğer Personel Sekmeleri (Kasa, Olay vb. V32'deki gibi devam eder...)        with tabs[1]: # Kasa             st.header("💰 Kasa İşlemleri")             # Kasa kodları...            # --- 🟢 KURUCU PANELİ (Analiz Alanı Güncellendi) ---    if role == "admin":        with tabs[0]: # Kurucu Raporu            st.header("📊 Günlük Durum Özeti")            t_sec_raw = st.date_input("Rapor Tarihi", datetime.now())            # Raporlama fonksiyonu ve gösterimi...        with tabs[1]: # Gelişmiş Analiz            st.header("📈 Finansal & Operasyonel Analiz")            df_gorus = conn.read(worksheet="gorusmeler", ttl=0)                        # PERSONEL BAZLI ANALİZ            st.subheader("👥 Personel Görüşme Performansı")            if "Görüşmeyi Yapan" in df_gorus.columns:                staff_perf = df_gorus['Görüşmeyi Yapan'].value_counts().reset_index()                staff_perf.columns = ['Personel', 'Görüşme Sayısı']                fig_staff = px.bar(staff_perf, x='Personel', y='Görüşme Sayısı', title="Kimin Kaç Görüşme Yaptığı", text_auto=True, color='Personel')                st.plotly_chart(fig_staff, use_container_width=True)            else:                st.info("Henüz 'Görüşmeyi Yapan' verisi bulunamadı.")                        # Diğer Grafikler (Finansal Pasta, Durum Dağılımı vb. V32'deki gibi...)